fn route_request(req: &Request) -> String {
    let path = req.get_path();
    let host = req
        .get_header_str("host")
        .unwrap_or("default");

    // Security: Use explicit routing logic with validation
    if path.starts_with("/api/") {
        "api_backend".to_string()
    } else if path.starts_with("/static/") {
        "static_backend".to_string()
    } else if path.starts_with("/admin/") {
        // Security: Additional validation for admin paths
        if is_authorized_admin(req) {
            "admin_backend".to_string()
        } else {
            "unauthorized".to_string()
        }
    } else if host.contains("cdn.") {
        "cdn_backend".to_string()
    } else {
        "default_backend".to_string()
    }
}

fn is_valid_backend(backend_name: &str) -> bool {
    // Security: Whitelist of allowed backends
    matches!(
        backend_name,
        "api_backend"
            | "static_backend"
            | "admin_backend"
            | "cdn_backend"
            | "default_backend"
    )
}

